function plainText = rail_fence_decipher(cipherText, depth)
    % Get the length of the ciphertext
    textLength = length(cipherText);
    % Initialize the rail matrix
    rail = char(zeros(depth, textLength));
    % Determine the zig-zag pattern of rows
    row = 1;
    direction = 1; % 1 for down, -1 for up
    pattern = zeros(1, textLength);
    for i = 1:textLength
        pattern(i) = row;
        if row == 1
            direction = 1; % change to down
        elseif row == depth
            direction = -1; % change to up
        end
        row = row + direction;
    end
    % Fill rail matrix with ciphertext characters based on pattern
    currentIndex = 1;
    for r = 1:depth
        for i = 1:textLength
            if pattern(i) == r
                rail(r, i) = cipherText(currentIndex);
                currentIndex = currentIndex + 1;
            end
        end
    end
    % Read plaintext from the rail matrix in zig-zag order
    plainText = '';
    for i = 1:textLength
        plainText = [plainText, rail(pattern(i), i)];
    end
end

function cipherText = rail_fence_cipher(plainText, depth)
    % Initialize an empty character array for the rails with specified depth
    rail = char(zeros(depth, length(plainText)));
    % Start at the first row and set the initial direction to "down" (1)
    row = 1;
    direction = 1; % 1 for moving down, -1 for moving up
    % Iterate over each character in the plain text
    for i = 1:length(plainText)
        % Place the current character in the appropriate row and column
        rail(row, i) = plainText(i);
        % Change direction at the top or bottom rail
        if row == 1
            direction = 1; % start moving down
        elseif row == depth
            direction = -1; % start moving up
        end
        % Move to the next row according to the current direction
        row = row + direction;
    end
    % Reshape the rail matrix to a single row and remove empty (zero) characters
    rail = reshape(rail.', 1, []);
    cipherText = rail(rail ~= 0); % remove zeros (empty spaces)
end

function cipherText = monoalphabetic_cipher(plainText, key)
    % Convert plainText to uppercase   
    plainText = upper(plainText);
    cipherText = '';
    % Define the alphabet
    alphabet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    % Encrypt each character
    for i = 1 : length(plainText)
        chr = plainText(i);
        if isletter(chr)
            % Find the position of the character in the alphabet
            index = find(alphabet == chr);
            % Substitute using the key
            cipherText = [cipherText, key(index)];
        else
            % Non-letter characters are added as is
            cipherText = [cipherText, chr];
        end
    end
end

