function plainText = columnar_decipher(cipherText, key)
    % Convert the key to uppercase to ensure consistent sorting
    key = upper(key);
    % Calculate the number of columns and rows needed for the cipher grid
    numCols = length(key);
    numRows = ceil(length(cipherText) / numCols);
    % Get the order of columns based on sorting the key alphabetically
    [~, sortedIdx] = sort(key);
    % Initialize an empty grid to hold the transposed ciphertext
    grid = char(zeros(numRows, numCols));
    % Fill the grid column by column according to the order of the sorted key
    currentIndex = 1;
    for i = 1:numCols
        col = sortedIdx(i); % Get the correct column index based on the key
        for row = 1:numRows
            if currentIndex <= length(cipherText)
                grid(row, col) = cipherText(currentIndex);
                currentIndex = currentIndex + 1;
            end
        end
    end
    % Read the plaintext from the grid row by row
    plainText = '';
    for row = 1:numRows
        for col = 1:numCols
            if grid(row, col) ~= 0 % Ignore empty cells
                plainText = [plainText, grid(row, col)];
            end
        end
    end
end

function cipherText = columnar_cipher(plainText, key)
    % Determine the number of columns based on the length of the key
    numCols = length(key);
    % Calculate the number of rows and pad the plaintext with 'X' if necessary
    numRows = ceil(length(plainText) / numCols);
    paddedLength = numRows * numCols;
    plainText = [plainText, repmat('X', 1, paddedLength - length(plainText))];
    % Create the columnar transposition matrix by reshaping the plaintext
    transpositionMatrix = reshape(plainText, numCols, numRows).';
    % Sort the columns based on the alphabetical order of the key
    [~, order] = sort(key);
    % Read columns in the order defined by the sorted key to build the ciphertext
    cipherText = ''; % Initialize ciphertext
    for i = 1:numCols
        cipherText = [cipherText, transpositionMatrix(:, order(i)).'];
    end
end

function plainText = otp_decipher(cipherText, key)
    % Convert cipher text to uppercase numeric values (A = 0, B = 1, ...)
    cipherTextNum = double(upper(cipherText)) - double('A');
    % Convert key to uppercase numeric values
    keyNum = double(upper(key)) - double('A');
    % Decrypt by subtracting key from cipher text and wrapping with mod 26
    plainTextNum = mod(cipherTextNum - keyNum, 26);
    % Convert numeric values back to characters for the plain text
    plainText = char(plainTextNum + double('A'));
end

function cipherText = otp_cipher(plainText, key)
    % Convert plain text to uppercase numeric values (A = 0, B = 1, ...)
    plainTextNum = double(upper(plainText)) - double('A');
    % Convert key to uppercase numeric values
    keyNum = double(upper(key)) - double('A');
    % Apply OTP cipher and wrap with mod 26
    cipherTextNum = mod(plainTextNum + keyNum, 26);
    % Convert numeric values back to characters
    cipherText = char(cipherTextNum + double('A'));
end
